};

//-------------------------------------------------------------------------
// 공통콤보 dataList ondataload
//-------------------------------------------------------------------------
scwin.ds_commonCombo_ondataload = function () {
    if (scwin.options.initIndex !== undefined || scwin.options.initIndex !== null) {
        lc_commonCombo.setSelectedIndex(scwin.options.initIndex);
        // DataMap이나 DataList 연동
        if (scwin.options.refDataCollection) {   
            scwin.syncRefDataCollection(
                lc_commonCombo.getValue(),
                ds_commonCombo.getCellData(lc_commonCombo.getSelectedIndex(), "name") || ""
            );
        }

        scwin.init = true;
        scwin.lc_commonCombo_onviewchange();
    }
};

