// ASIS 호환 동작은 하단에서 한 번 더 재정의한다.
scwin.lc_commonCombo_onviewchange = function (info) {
    const idx = lc_commonCombo.getSelectedIndex();
    if (idx === undefined || idx === null || idx < 0) {
        return;
    }

    const code = ds_commonCombo.getCellData(idx, "code") || "";
    const name = ds_commonCombo.getCellData(idx, "name") || "";
    const sub = ds_commonCombo.getCellData(idx, "sub") || "";

    scwin.syncRefDataCollection(code, name);
    ed_commonComboName.setValue(name);
    scwin.syncLegacyMirrorFields(name);

    if (scwin.options.cascadeTargetId) {
        scwin.syncCascadeTarget(sub);
    } else if (scwin.options.cond == "HOFC") {
        const offIdxs = sub.split("/");

        if (!scwin.options.refHiddenDataCollection) {
            console.warn("[commonCombo] cond가 HOFC일 경우 refHiddenDataCollection은 필수 속성 입니다.");
        }

        const hiddenDataMap = scwin.getParentComponent(scwin.options.refHiddenDataCollection);
        if (hiddenDataMap) {
            hiddenDataMap.set("hdoIdx", offIdxs[0]);
            hiddenDataMap.set("bhoIdx", offIdxs[1]);
            hiddenDataMap.set("offIdx", offIdxs[2]);
        }
    } else if (scwin.options.cond == "carType") {
        const carTypeCallbackFn = scwin.pFrame?.scwin?.f_vehclNrm;
        if (typeof carTypeCallbackFn === "function") {
            carTypeCallbackFn(lc_commonCombo.getValue());
        }
    }

    if (scwin.init) {
        scwin.init = false;
        const fn = scwin.options.initFunction;
        const parentScwin = scwin.pFrame?.scwin;

        if (fn && typeof parentScwin?.[fn] === "function") {
            parentScwin[fn]();
        }
    }
};

scwin.ds_commonCombo_ondataload = function () {
    const rowCount = typeof ds_commonCombo.getRowCount === "function" ? ds_commonCombo.getRowCount() : 0;
    if (rowCount < 1) {
        return;
    }

    const hasInitIndex = scwin.options.initIndex !== undefined
        && scwin.options.initIndex !== null
        && scwin.options.initIndex !== "";
    const requestedIndex = hasInitIndex ? Number(scwin.options.initIndex) : 0;
    const selectedIndex = Number.isInteger(requestedIndex) && requestedIndex >= 0 && requestedIndex < rowCount
        ? requestedIndex
        : 0;

    lc_commonCombo.setSelectedIndex(selectedIndex);
    scwin.init = true;
    scwin.lc_commonCombo_onviewchange();
};

// 최종 override: 선택값 반영 시점을 공통으로 맞춘다.
scwin.setSelectIndex = function (index) {
    lc_commonCombo.setSelectedIndex(index);
    scwin.syncSelection();
};

scwin.setValue = function (value) {
    lc_commonCombo.setValue(value);
    scwin.syncSelection();
};

scwin.lc_commonCombo_onviewchange = function (info) {
    if (!scwin.syncSelection()) {
        return;
    }

    if (scwin.init) {
        scwin.init = false;
        const fn = scwin.options.initFunction;
        const parentScwin = scwin.pFrame?.scwin;

        if (fn && typeof parentScwin?.[fn] === "function") {
            parentScwin[fn]();
        }
    }
};

scwin.ds_commonCombo_ondataload = function () {
    const rowCount = typeof ds_commonCombo.getRowCount === "function" ? ds_commonCombo.getRowCount() : 0;
    if (rowCount < 1) {
        return;
    }

    const boundCode = scwin.getRefBoundCode();
    let selectedIndex = boundCode !== "" ? scwin.findComboIndexByCode(boundCode) : -1;

    const hasInitIndex = scwin.options.initIndex !== undefined
        && scwin.options.initIndex !== null
        && scwin.options.initIndex !== "";
    if (selectedIndex < 0 && hasInitIndex) {
        const requestedIndex = Number(scwin.options.initIndex);
        if (Number.isInteger(requestedIndex) && requestedIndex >= 0 && requestedIndex < rowCount) {
            selectedIndex = requestedIndex;
        }
    }

    if (selectedIndex < 0) {
        const currentValue = ((typeof lc_commonCombo.getValue === "function" ? lc_commonCombo.getValue() : "") ?? "").toString().trim();
        if (currentValue !== "") {
            selectedIndex = scwin.findComboIndexByCode(currentValue);
        }
    }

    if (selectedIndex < 0) {
        if (scwin.hasPlaceholder()) {
            lc_commonCombo.setSelectedIndex(-1);
            scwin.clearSelectionEffects({ writeRef: false });
            return;
        }

        selectedIndex = 0;
    }

    lc_commonCombo.setSelectedIndex(selectedIndex);
    scwin.init = true;
    scwin.lc_commonCombo_onviewchange();
    scwin.deferRefreshSelectionFromRef();
};



